import { useState, useEffect } from "react";

const CONFIG = {
  name: "민지",
  giftName: "인라인 스케이트",
  goal: 300000,
  birthday: "2026-07-01",
  kakaoLink: "https://qr.kakaopay.com/Ej8Xra0Tq",
  scriptUrl: "https://script.google.com/macros/s/AKfycbwhaTlgCrgufV17EJYKYKnnMSs_O_EyfhIIdNd8dQzc5BYWkXwJ-BL_oFptmCnSRxPuWw/exec",
  thankMsg: "후원해 주신다면 성실하고 바르게 자라겠습니다",
};

const KONGI_IMG = "data:image/png;base64,";
const INLINE_IMG = "data:image/jpeg;base64,";

const C = {
  bg:       "#FFFFFF",
  yellow:   "#C8E6FF",
  yellowLt: "#EAF4FF",
  green:    "#B8F0A0",
  greenDk:  "#4CAF50",
  greenLt:  "#EDFCE7",
  text:     "#191F28",
  sub:      "#8B95A1",
  border:   "#F2F4F6",
  card:     "#F8F9FA",
  blue:     "#3D8BFF",
  blueDk:   "#1A6FE0",
};

function getDday() {
  const now    = new Date();
  const target = new Date(CONFIG.birthday);
  const diff   = Math.ceil((target - now) / (1000 * 60 * 60 * 24));
  return diff;
}
function formatWon(n) {
  return Number(n).toLocaleString("ko-KR") + "원";
}

const ADMIN_PW = "5501";

const EDIT_FIELDS = [
  { key: "headerTitle",  label: "헤더 타이틀 (이모지 포함)", type: "input" },
  { key: "name",        label: "이름",                    type: "input" },
  { key: "giftName",    label: "선물 이름",                type: "input" },
  { key: "goal",        label: "목표 금액 (숫자)",          type: "input" },
  { key: "forLine",     label: "메인 한 줄 멘트",           type: "textarea", rows: 2 },
  { key: "thankMsg",    label: "감사 박스 멘트",            type: "textarea", rows: 2 },
  { key: "doneDesc",    label: "후원 완료 설명",            type: "textarea", rows: 2 },
  { key: "thanksTitle", label: "감사 화면 제목",            type: "input" },
];

function EditPanel({ editConfig, setEditConfig, showToast, styles: s, colors: C }) {
  function handleSave() {
    try {
      localStorage.setItem("editConfig", JSON.stringify(editConfig));
      showToast("저장 완료!");
    } catch { showToast("저장 실패!"); }
  }
  return (
    <div style={s.editPanel}>
      <div style={s.editTitle}>✏️ 편집 모드</div>
      {EDIT_FIELDS.map(({ key, label, type, rows }) => (
        <div key={key} style={s.editRow}>
          <div style={s.editLabel}>{label}</div>
          {type === "input"
            ? <input
                style={s.editInput}
                value={editConfig[key]}
                onChange={e => setEditConfig(p => ({ ...p, [key]: key === "goal" ? Number(e.target.value) : e.target.value }))}
              />
            : <textarea
                style={s.editTextarea}
                rows={rows}
                value={editConfig[key]}
                onChange={e => setEditConfig(p => ({ ...p, [key]: e.target.value }))}
              />
          }
        </div>
      ))}
      <button style={s.editSaveBtn} onClick={handleSave}>저장</button>
    </div>
  );
}

export default function App() {
  const [screen, setScreen]               = useState("main");
  const [inputAmount, setInputAmount]     = useState("");
  const [name, setName]                   = useState("");
  const [message, setMessage]             = useState("");
  const [pendingAmount, setPendingAmount] = useState(0);
  const [records, setRecords]             = useState([]);
  const [submitting, setSubmitting]       = useState(false);
  const [toast, setToast]                 = useState("");
  const [loading, setLoading]             = useState(true);

  // 관리자
  const [adminMode, setAdminMode]         = useState(false);
  const [pwInput, setPwInput]             = useState("");
  const [showPwModal, setShowPwModal]     = useState(false);
  const defaultConfig = {
    headerTitle: "🛼 민지의 생일 펀딩",
    name: CONFIG.name,
    giftName: CONFIG.giftName,
    goal: CONFIG.goal,
    forLine: "진짜 제발 저요 정말 간절합니다 저 당장 타고 싶습니다",
    thankMsg: CONFIG.thankMsg,
    doneDesc: "인라인으로 성장하는 제 모습을\n지켜봐 주세요",
    thanksTitle: "이 은혜 잊지 않겠습니다",
  };

  const [editConfig, setEditConfig] = useState(() => {
    try {
      const saved = localStorage.getItem("editConfig");
      return saved ? { ...defaultConfig, ...JSON.parse(saved) } : defaultConfig;
    } catch { return defaultConfig; }
  });

  const dday        = getDday();
  const total       = records.reduce((s, r) => s + (Number(r.amount) || 0), 0);
  const validCount  = records.filter(r => Number(r.amount) > 0).length;
  const percent     = Math.min(100, Math.round((total / editConfig.goal) * 100)) || 0;
  const participants = validCount;

  function handleAdminLogin() {
    if (pwInput === ADMIN_PW) {
      setAdminMode(true);
      setShowPwModal(false);
      setPwInput("");
      showToast("관리자 모드 활성화!");
    } else {
      showToast("비밀번호가 틀렸어요");
      setPwInput("");
    }
  }

  useEffect(() => { fetchRecords(); }, []);

  async function fetchRecords() {
    setLoading(true);
    try {
      const res  = await fetch(`${CONFIG.scriptUrl}?action=get`);
      const data = await res.json();
      setRecords(data || []);
    } catch { setRecords([]); }
    setLoading(false);
  }

  function showToast(msg) {
    setToast(msg);
    setTimeout(() => setToast(""), 2500);
  }

  function handleAmountInput(e) {
    const raw = e.target.value.replace(/[^0-9]/g, "");
    setInputAmount(raw ? Number(raw).toLocaleString("ko-KR") : "");
  }

  function handleGoToPay() {
    const val = parseInt(inputAmount.replace(/,/g, "") || "0");
    if (!val || val < 1) { showToast("금액을 입력해주세요"); return; }
    setPendingAmount(val);
    window.open(CONFIG.kakaoLink, "_blank");
    setScreen("done");
  }

  async function handleConfirm() {
    if (!name.trim()) { showToast("이름을 입력해 주세요!"); return; }
    setSubmitting(true);
    try {
      await fetch(CONFIG.scriptUrl, {
        method: "POST", mode: "no-cors",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "add", name: name.trim(), amount: pendingAmount, message: message.trim() }),
      });
      setRecords(prev => [...prev, { name: name.trim(), amount: pendingAmount, message: message.trim() }]);
      setScreen("thanks");
    } catch { showToast("오류가 났어요. 다시 시도해 주세요!"); }
    setSubmitting(false);
  }

  const s = {
    wrap: {
      maxWidth: 430, margin: "0 auto", minHeight: "100dvh",
      background: C.bg,
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', sans-serif",
      paddingBottom: 56,
      position: "relative",
    },

    /* 헤더 */
    header: {
      background: C.blue, padding: "16px 20px",
      display: "flex", alignItems: "center", gap: 10,
      position: "sticky", top: 0, zIndex: 10,
    },
    backBtn: {
      background: "rgba(255,255,255,0.2)", border: "none", borderRadius: 50,
      width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center",
      fontSize: 16, cursor: "pointer", color: "#fff", fontWeight: 700,
    },
    headerTitle: { fontSize: 16, fontWeight: 700, color: "#fff" },

    /* 이미지 */
    imgBox: {
      width: "100%", aspectRatio: "1/1", overflow: "hidden",
      background: C.card,
    },
    img: { width: "100%", height: "100%", objectFit: "contain" },

    /* 섹션 구분 */
    section: { padding: "20px 20px 0" },
    divider: { height: 8, background: C.card, margin: "0" },

    /* 타이틀 블록 */
    titleRow: { display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 4 },
    giftName: { fontSize: 20, fontWeight: 800, color: C.text },
    ddayChip: {
      background: C.blue, color: "#fff",
      borderRadius: 8, padding: "4px 10px",
      fontSize: 13, fontWeight: 800, letterSpacing: "-0.3px",
    },
    forLine: { fontSize: 13, color: C.sub, marginBottom: 20 },

    /* 프로그레스 */
    progressBg: {
      height: 10, background: C.border, borderRadius: 99,
      overflow: "hidden", marginBottom: 10,
    },
    progressFill: {
      height: "100%",
      background: `linear-gradient(90deg, ${C.blue}, ${C.green})`,
      borderRadius: 99, transition: "width 0.7s ease",
    },
    amountRow: {
      display: "flex", justifyContent: "space-between",
      alignItems: "flex-end", marginBottom: 6,
    },
    currentAmt: { fontSize: 26, fontWeight: 800, color: C.text },
    goalAmt: { fontSize: 13, color: C.sub },
    statsRow: { display: "flex", justifyContent: "space-between", marginBottom: 24 },
    statTxt: { fontSize: 12, color: C.sub },
    statBold: { fontWeight: 700, color: C.blue },

    /* 서브 카드 */
    subRow: { display: "flex", gap: 10, marginBottom: 0 },
    subBox: {
      flex: 1, background: C.card, borderRadius: 14,
      padding: "14px 16px",
    },
    subLabel: { fontSize: 12, color: C.sub, marginBottom: 6 },
    subVal: { fontSize: 17, fontWeight: 800, color: C.text },

    /* 참여자 */
    participantSection: { padding: "20px 20px 0" },
    sectionLabel: { fontSize: 13, fontWeight: 700, color: C.sub, marginBottom: 14 },
    recordRow: {
      display: "flex", justifyContent: "space-between", alignItems: "center",
      padding: "13px 0", borderBottom: `1px solid ${C.border}`,
    },
    recordLeft: { display: "flex", alignItems: "center", gap: 10 },
    avatar: {
      width: 34, height: 34, borderRadius: 50,
      background: C.yellowLt, display: "flex",
      alignItems: "center", justifyContent: "center",
      fontSize: 15, fontWeight: 700, color: C.text,
    },
    recordName: { fontSize: 15, fontWeight: 600, color: C.text },
    recordAmt: { fontSize: 15, fontWeight: 700, color: C.text },

    /* 메인 버튼 */
    mainBtnWrap: { padding: "16px 20px 0" },
    mainBtn: {
      width: "100%", padding: "17px",
      background: C.blue, color: "#fff",
      border: "none", borderRadius: 14,
      fontSize: 16, fontWeight: 800, cursor: "pointer",
      letterSpacing: "-0.3px",
    },

    /* 금액 입력 */
    amtLabel: { fontSize: 22, fontWeight: 800, color: C.text, marginBottom: 6 },
    amtSub: { fontSize: 14, color: C.sub, marginBottom: 28 },
    inputWrap: {
      display: "flex", alignItems: "center",
      borderBottom: `2px solid ${C.text}`, paddingBottom: 8,
      marginBottom: 8,
    },
    input: {
      flex: 1, border: "none", background: "transparent",
      fontSize: "max(16px, 36px)", fontWeight: 800, outline: "none",
      color: C.text, padding: 0,
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', sans-serif",
    },
    inputWon: { fontSize: 20, fontWeight: 700, color: C.sub },
    inputHelper: { fontSize: 12, color: C.sub, marginBottom: 32 },

    /* 감사 문구 박스 */
    thankBox: {
      background: C.greenLt, borderRadius: 14,
      padding: "18px 20px", marginBottom: 20,
    },
    thankTxt: { fontSize: 14, color: C.text, lineHeight: 1.9, whiteSpace: "pre-line" },

    /* 완료 화면 */
    doneWrap: { padding: "48px 20px 0", textAlign: "center" },
    doneBig: { fontSize: 64, marginBottom: 16 },
    doneTitle: { fontSize: 22, fontWeight: 800, color: C.text, marginBottom: 8 },
    doneDesc: { fontSize: 14, color: C.sub, lineHeight: 1.8, marginBottom: 32, whiteSpace: "pre-line" },
    nameInputWrap: {
      background: C.card, borderRadius: 14,
      padding: "4px 16px", display: "flex",
      alignItems: "center", marginBottom: 12, textAlign: "left",
    },
    nameInput: {
      flex: 1, border: "none", background: "transparent",
      fontSize: 16, outline: "none", padding: "16px 0",
      color: C.text,
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', sans-serif",
    },
    amtChip: {
      display: "inline-block",
      background: C.yellowLt, borderRadius: 8,
      padding: "6px 14px", fontSize: 14,
      fontWeight: 700, color: C.blue, marginBottom: 0,
    },

    ghostBtn: {
      width: "100%", padding: "15px",
      background: "transparent", color: C.sub,
      border: `1px solid ${C.border}`, borderRadius: 14,
      fontSize: 15, cursor: "pointer", marginTop: 8,
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', sans-serif",
    },

    toast: {
      position: "fixed", bottom: 32, left: "50%",
      transform: "translateX(-50%)",
      background: C.text, color: "#fff",
      padding: "13px 22px", borderRadius: 30,
      fontSize: 14, zIndex: 999, whiteSpace: "nowrap",
      boxShadow: "0 4px 20px rgba(0,0,0,0.15)",
    },

    // 관리자
    adminBtn: {
      marginLeft: "auto", background: adminMode ? C.blue : C.card,
      border: "none", borderRadius: 8, padding: "6px 12px",
      fontSize: 12, fontWeight: 700, color: adminMode ? "#fff" : C.sub,
      cursor: "pointer",
    },
    modal: {
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.4)",
      display: "flex", alignItems: "center", justifyContent: "center", zIndex: 200,
    },
    modalBox: {
      background: "#fff", borderRadius: 20, padding: "28px 24px",
      width: 300, boxShadow: "0 8px 32px rgba(0,0,0,0.15)",
    },
    modalTitle: { fontSize: 17, fontWeight: 800, color: C.text, marginBottom: 16, textAlign: "center" },
    modalInput: {
      width: "100%", padding: "13px 16px", border: `2px solid ${C.border}`,
      borderRadius: 12, fontSize: 16, outline: "none", boxSizing: "border-box",
      marginBottom: 12, textAlign: "center", letterSpacing: 6,
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', sans-serif",
    },
    modalBtn: {
      width: "100%", padding: "14px", background: C.blue, color: "#fff",
      border: "none", borderRadius: 12, fontSize: 15, fontWeight: 700, cursor: "pointer",
    },
    modalCancel: {
      width: "100%", padding: "12px", background: "transparent", color: C.sub,
      border: "none", fontSize: 14, cursor: "pointer", marginTop: 6,
    },
    editPanel: {
      background: C.yellowLt, margin: "0 0 0 0", padding: "16px 20px",
      borderBottom: `1px solid ${C.border}`,
    },
    editTitle: { fontSize: 13, fontWeight: 800, color: C.blue, marginBottom: 12 },
    editRow: { marginBottom: 10 },
    editLabel: { fontSize: 11, color: C.sub, marginBottom: 4, fontWeight: 600 },
    editInput: {
      width: "100%", padding: "10px 12px", border: `1.5px solid ${C.border}`,
      borderRadius: 10, fontSize: 14, outline: "none", boxSizing: "border-box",
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', sans-serif", color: C.text,
    },
    editTextarea: {
      width: "100%", padding: "10px 12px", border: `1.5px solid ${C.border}`,
      borderRadius: 10, fontSize: 14, outline: "none", boxSizing: "border-box",
      fontFamily: "'Pretendard', 'Apple SD Gothic Neo', sans-serif", color: C.text,
      resize: "none", lineHeight: 1.6,
    },
    editSaveBtn: {
      width: "100%", padding: "12px", background: C.blue, color: "#fff",
      border: "none", borderRadius: 10, fontSize: 14, fontWeight: 700,
      cursor: "pointer", marginTop: 4,
    },
  };

  // ─── 비밀번호 모달 ───
  const PwModal = () => (
    <div style={s.modal} onClick={() => setShowPwModal(false)}>
      <div style={s.modalBox} onClick={e => e.stopPropagation()}>
        <div style={s.modalTitle}>관리자 로그인</div>
        <input
          style={s.modalInput}
          type="password"
          inputMode="numeric"
          pattern="[0-9]*"
          placeholder="••••"
          value={pwInput}
          onChange={e => setPwInput(e.target.value)}
          onKeyDown={e => e.key === "Enter" && handleAdminLogin()}
          autoFocus
        />
        <button style={s.modalBtn} onClick={handleAdminLogin}>확인</button>
        <button style={s.modalCancel} onClick={() => { setShowPwModal(false); setPwInput(""); }}>취소</button>
      </div>
    </div>
  );

  // ─── 관리자 편집 패널 ───
  // ─── 메인 ───
  if (screen === "main") return (
    <div style={s.wrap}>
      <div style={s.header}>
        <span style={s.headerTitle}>{editConfig.headerTitle}</span>
        <button style={s.adminBtn} onClick={() => adminMode ? setAdminMode(false) : setShowPwModal(true)}>
          {adminMode ? "편집 종료" : "관리자"}
        </button>
      </div>
      {showPwModal && <PwModal />}
      {adminMode && <EditPanel editConfig={editConfig} setEditConfig={setEditConfig} showToast={showToast} styles={s} colors={C} />}

      <div style={s.imgBox}>
        <img src={INLINE_IMG} alt="선물" style={s.img} />
      </div>

      <div style={s.section}>
        <div style={{ height: 20 }} />
        <div style={s.titleRow}>
          <span style={s.giftName}>{editConfig.giftName} 🎁</span>
          <span style={s.ddayChip}>D-{dday}</span>
        </div>
        <div style={s.forLine}>{editConfig.forLine}</div>

        {loading ? (
          <div style={{ padding: "20px 0", textAlign: "center", color: C.sub, fontSize: 14 }}>
            불러오는 중...
          </div>
        ) : (
          <>
            <div style={s.amountRow}>
              <span style={s.currentAmt}>{formatWon(total)}</span>
              <span style={s.goalAmt}>목표 {formatWon(editConfig.goal)}</span>
            </div>
            <div style={s.progressBg}>
              <div style={{ ...s.progressFill, width: `${percent}%` }} />
            </div>
            <div style={s.statsRow}>
              <span style={s.statTxt}><span style={s.statBold}>{percent}%</span> 달성</span>
              <span style={s.statTxt}>참여자 <span style={s.statBold}>{participants}명</span></span>
            </div>
            <div style={s.subRow}>
              <div style={s.subBox}>
                <div style={s.subLabel}>남은 금액</div>
                <div style={s.subVal}>{formatWon(Math.max(0, editConfig.goal - total))}</div>
              </div>
              <div style={s.subBox}>
                <div style={s.subLabel}>평균 참여금액</div>
                <div style={s.subVal}>{participants > 0 ? formatWon(Math.round(total / participants)) : "—"}</div>
              </div>
            </div>
          </>
        )}
      </div>

      <div style={s.mainBtnWrap}>
        <button style={s.mainBtn} onClick={() => setScreen("amount")}>
          선물하기 🎉
        </button>
      </div>
      {toast && <div style={s.toast}>{toast}</div>}
    </div>
  );

  // ─── 금액 입력 ───
  if (screen === "amount") {
    const val = parseInt(inputAmount.replace(/,/g, "") || "0");
    return (
      <div style={s.wrap}>
        <div style={s.header}>
          <button style={s.backBtn} onClick={() => setScreen("main")}>←</button>
          <span style={s.headerTitle}>후원하기</span>
        </div>

        <div style={{ ...s.section, paddingTop: 32 }}>
          <div style={s.thankBox}>
            <div style={s.thankTxt}>{editConfig.thankMsg}</div>
          </div>

          <div style={{ textAlign: "center", margin: "20px 0 8px" }}>
            <img src={KONGI_IMG} alt="콩이" style={{ width: 160, height: "auto", display: "inline-block" }} />
            <div style={{ fontSize: 13, color: C.sub, marginTop: 4 }}>콩이를 사랑하는 만큼 ☞</div>
          </div>

          <div style={s.amtLabel}>후원 금액</div>
          <div style={s.amtSub}>금액을 입력해 주세요</div>

          <div style={s.inputWrap}>
            <input
              style={s.input}
              type="text"
              inputMode="numeric"
              placeholder="0"
              value={inputAmount}
              onChange={handleAmountInput}
            />
            <span style={s.inputWon}>원</span>
          </div>
          <div style={s.inputHelper}> </div>
        </div>

        <div style={s.mainBtnWrap}>
          <button style={{
            ...s.mainBtn,
            background: val >= 1 ? C.blue : C.border,
            color: val >= 1 ? "#fff" : C.sub,
          }} onClick={handleGoToPay}>
            카카오톡으로 송금하기
          </button>
        </div>
        {toast && <div style={s.toast}>{toast}</div>}
      </div>
    );
  }

  // ─── 후원 확인 ───
  if (screen === "done") return (
    <div style={s.wrap}>
      <div style={s.header}>
        <span style={s.headerTitle}>후원 확인</span>
      </div>
      <div style={s.doneWrap}>
        <div style={s.doneBig}>🎉</div>
        <div style={s.doneTitle}>후원이 완료되었습니다!</div>
        <div style={s.doneDesc}>{editConfig.doneDesc}</div>
        <div style={s.nameInputWrap}>
          <input
            style={s.nameInput}
            type="text"
            placeholder="이름 또는 닉네임 입력"
            value={name}
            onChange={e => setName(e.target.value)}
            maxLength={10}
          />
        </div>
        <div style={{ ...s.nameInputWrap, marginBottom: 16 }}>
          <input
            style={s.nameInput}
            type="text"
            placeholder="생일 축하 한마디 남기기 🎂"
            value={message}
            onChange={e => setMessage(e.target.value)}
            maxLength={30}
          />
        </div>
        <div style={{ marginBottom: 28 }}>
          <span style={s.amtChip}>후원 금액 {formatWon(pendingAmount)}</span>
        </div>
      </div>
      <div style={s.mainBtnWrap}>
        <button style={s.mainBtn} onClick={handleConfirm} disabled={submitting}>
          {submitting ? "처리 중..." : "후원 완료 ✅"}
        </button>
        <button style={s.ghostBtn} onClick={() => setScreen("amount")}>다시 입력할게요</button>
      </div>
      {toast && <div style={s.toast}>{toast}</div>}
    </div>
  );

  // ─── 감사 ───
  if (screen === "thanks") return (
    <div style={s.wrap}>
      <div style={{ ...s.doneWrap }}>
        <div style={s.doneBig}>🛼</div>
        <div style={s.doneTitle}>{editConfig.thanksTitle}</div>
        <div style={s.doneDesc}>{editConfig.thankMsg}</div>
      </div>
      <div style={s.mainBtnWrap}>
        <button style={s.mainBtn} onClick={() => setScreen("main")}>
          펀딩 현황 보기
        </button>
      </div>
    </div>
  );
}
